1445	@@ -0,0 +1,81 @@
1446	+/**
1447	+ * Read-path id-backfill normalization (ADR 0006 consequence, registration-launch
1448	+ * Branch 2 sub-commit 2.1).
1449	+ *
1450	+ * Every CMS list item now carries a *required* `id: ListItemId` (a `nanoid`) so
1451	+ * the editor can address it by identity rather than by array position. But every
1452	+ * `content/site.json` already published BEFORE this change has no ids, so a
1453	+ * required `id` would make the live document FAIL decode on the next read — the
1454	+ * deploy would break the public site on its own content.
1455	+ *
1456	+ * The fix is a one-shot repair at the read boundary: before the document is
1457	+ * Schema-decoded, `backfillListItemIds` walks the parsed (untrusted) JSON and
1458	+ * assigns a fresh `nanoid` to any list item that lacks an `id`. It is a pure
1459	+ * structural normalization — NOT a parallel schema and NOT validation:
1460	+ *   - `derive-dont-sync`: there is one decode boundary; this only fills the gap
1461	+ *     a pre-ids document leaves, so the decoded value is always id-complete.
1462	+ *   - `make-operations-idempotent`: an item that already has an `id` key is left
1463	+ *     untouched (even a *bad* id is left for the decoder to reject — backfill is
1464	+ *     for absence, not repair), so re-running on an already-migrated document is
1465	+ *     a no-op. The first admin publish persists the backfilled ids; from then on
1466	+ *     the normalization changes nothing.
1467	+ *   - `boundary-discipline`: it runs only over already-parsed JSON inside the
1468	+ *     read path, never mutates its input, and hands a fresh value to the decoder
1469	+ *     which remains the sole gate that brands the ids. The input is `unknown`
1470	+ *     (raw parsed JSON), so the walk narrows defensively and never trusts shape.
1471	+ *
1472	+ * The list-item locations are the three id-bearing structs the schema names
1473	+ * today (`Speaker`, `Seminar`, `TeamMember`); Branch 3+ widens them as the
1474	+ * Conference / Page schemas grow id-bearing lists, and this walk grows with
1475	+ * them. The walk descends only into the arrays/objects that are actually present
1476	+ * and the expected shape, so a malformed document still reaches the decoder
1477	+ * (which rejects it) rather than throwing here.
1478	+ */
1479	+
1480	+import { newListItemId } from './schema';
1481	+import type { Json } from './admin-form';
1482	+
1483	+const isObject = (value: unknown): value is { readonly [key: string]: Json } =>
1484	+  typeof value === 'object' && value !== null && !Array.isArray(value);
1485	+
1486	+/** Assign a fresh id to a list item that has no `id` key; else leave it alone. */
1487	+const withId = (item: Json): Json => {
1488	+  if (!isObject(item)) return item;
1489	+  if ('id' in item) return item;
1490	+  return { id: newListItemId(), ...item };
1491	+};
1492	+
1493	+/** Backfill ids on every element of `value` when it is an array of items. */
1494	+const backfillItems = (value: unknown): readonly Json[] | undefined =>
1495	+  Array.isArray(value) ? value.map(withId) : undefined;
1496	+
1497	+/**
1498	+ * Return a copy of the parsed `SiteContent` JSON with a fresh id assigned to any
1499	+ * id-less list item (`conferences[].speakers[]`, `conferences[].seminars[]`,
1500	+ * `team[]`). Items already carrying an `id` are untouched (idempotent). A value
1501	+ * that is not the expected shape is returned as-is so the decoder — not this
1502	+ * normalizer — is the one to reject it.
1503	+ */
1504	+export const backfillListItemIds = (document: unknown): unknown => {
1505	+  if (!isObject(document)) return document;
1506	+
1507	+  const next: Record<string, Json> = { ...document };
1508	+
1509	+  const conferences = document['conferences'];
1510	+  if (Array.isArray(conferences)) {
1511	+    next['conferences'] = conferences.map((conference: Json) => {
1512	+      if (!isObject(conference)) return conference;
1513	+      const conf: Record<string, Json> = { ...conference };
1514	+      const speakers = backfillItems(conference['speakers']);
1515	+      if (speakers !== undefined) conf['speakers'] = speakers;
1516	+      const seminars = backfillItems(conference['seminars']);
1517	+      if (seminars !== undefined) conf['seminars'] = seminars;
1518	+      return conf;
1519	+    });
1520	+  }
1521	+
1522	+  const team = backfillItems(document['team']);
1523	+  if (team !== undefined) next['team'] = team;
1524	+
1525	+  return next;
1526	+};
