 88	export const loader = routeHandler(function* () {
 89	  const { request } = yield* ReactRouterContext;
 90	  const auth = yield* Auth.Service;
 91	  // 404 the whole area when disabled; the layout guard already redirected an
 92	  // unauthenticated visitor, but re-checking keeps this route safe on its own.
 93	  yield* auth.checkCookie(request.headers.get('cookie')).pipe(
 94	    Effect.catchTags({
 95	      'Auth.Disabled': () =>
 96	        Effect.fail(new Response('Not Found', { status: 404 })),
 97	      'Auth.Unauthorized': () => Effect.fail(redirect('/admin/login')),
 98	    }),
 99	  );
100	
101	  const editor = yield* DraftEditor.Service;
102	  const env = yield* Env.Service;
103	  const { content: document, source } = yield* editor.load(siteScope);
104	  const encoded = yield* encodeDocument(document);
105	
106	  // The bucket is "configured" exactly when `Env.bucket` is present — the single
107	  // source of truth (a bucket-less editor still renders so the admin can preview,
108	  // but saving/publishing would fail, which we warn about up front).
109	  const bucketConfigured = Option.isSome(env.bucket);
110	
111	  return { document: encoded as EncodedDocument, source, bucketConfigured };
112	});
