114	export const action = routeAction(function* () {
115	  const { request } = yield* ReactRouterContext;
116	  const auth = yield* Auth.Service;
117	  yield* auth.checkCookie(request.headers.get('cookie')).pipe(
118	    Effect.catchTags({
119	      'Auth.Disabled': () =>
120	        Effect.fail(new Response('Not Found', { status: 404 })),
121	      'Auth.Unauthorized': () => Effect.fail(redirect('/admin/login')),
122	    }),
123	  );
124	
125	  const editor = yield* DraftEditor.Service;
126	  const storage = yield* Storage.Service;
127	  const form = yield* Effect.promise(() => request.formData());
128	  const intent = String(form.get('intent') ?? 'save-draft');
129	
130	  // ---- image upload --------------------------------------------------------
131	  // The route owns the FormData side: validate the file and store its raw bytes;
132	  // `DraftEditor.applyImageUpload` then rewrites the targeted `…key` field on the
133	  // draft so the new image survives a reload and a later publish.
134	  const uploadTarget = imageUploadTarget(intent);
135	  if (uploadTarget !== null) {
136	    const file = form.get('file');
137	    if (!(file instanceof File) || file.size === 0) {
138	      return Response.json(
139	        { ok: false, error: 'Choose an image before uploading.', issues: [] },
140	        { status: 400 },
141	      );
142	    }
143	    if (!isAcceptedImageType(file.type)) {
144	      return Response.json(
145	        {
146	          ok: false,
147	          error: 'Upload a JPEG, PNG, WebP, GIF, or AVIF image.',
148	          issues: [],
149	        },
150	        { status: 400 },
151	      );
152	    }
153	
154	    const now = yield* Clock.currentTimeMillis;
155	    const key = uploadedImageKey(uploadTarget, file.type, now);
156	    const bytes = new Uint8Array(yield* Effect.promise(() => file.arrayBuffer()));
157	
158	    const putExit = yield* Effect.exit(storage.put(key, bytes, file.type));
159	    if (putExit._tag === 'Failure') {
160	      return Response.json(
161	        {
162	          ok: false,
163	          error:
164	            'Image upload failed — is the bucket configured? ' +
165	            Cause.pretty(putExit.cause),
166	          issues: [],
167	        },
168	        { status: 502 },
169	      );
170	    }
171	
172	    const applied = yield* editor
173	      .applyImageUpload(siteScope, uploadTarget, key)
174	      .pipe(Effect.result);
175	    if (applied._tag === 'Failure') return issueResponse(applied.failure);
176	    return redirect(
177	      `/admin/content?status=${encodeURIComponent(`Image uploaded: ${key}`)}`,
178	    );
179	  }
180	
181	  // ---- list op (add / remove / reorder) ------------------------------------
182	  // A per-list Add / Remove / reorder control submits `list:<path>:<kind>` fields
183	  // (ADR 0006). The route parses them into `ListOp`s; `DraftEditor.applyListOps`
184	  // performs the id-keyed structural edit on the draft and auto-saves it (settled
185	  // #10) so a freshly-added item's id exists server-side before a photo upload /
186	  // field edit targets it. An "Add" appends an item carrying only its id — draft-
187	  // valid, publish-invalid until its bilingual fields are filled (ADR 0006).
188	  if (intent === 'list-op') {
189	    const ops = collectListOps(form.entries());
190	    if (ops.length === 0) {
191	      return Response.json(
192	        { ok: false, error: 'No list change to apply.', issues: [] },
193	        { status: 400 },
194	      );
195	    }
196	    const applied = yield* editor.applyListOps(siteScope, ops).pipe(Effect.result);
197	    if (applied._tag === 'Failure') return issueResponse(applied.failure);
198	    return redirect('/admin/content?status=List%20updated.');
199	  }
200	
201	  if (intent !== 'save-draft' && intent !== 'publish') {
202	    return Response.json(
203	      { ok: false, error: 'Unknown submit intent.', issues: [] },
204	      { status: 400 },
205	    );
206	  }
207	
208	  // ---- save / publish ------------------------------------------------------
209	  // Parse the form into ONE override: dotted-path fields via `assembleOverrides`,
210	  // plus the `t:<locale>:<key>` translation fields folded onto `translations`
211	  // (their keys carry dots, so they can't ride the dotted-path convention).
212	  // `DraftEditor.editDocument` merges it onto the current document, decodes at
213	  // the single boundary, and stores the draft.
214	  const override = deepMerge(assembleOverrides(form.entries()), {
215	    translations: collectTranslations(form.entries()),
216	  } as Json);
217	
218	  const edited = yield* editor
219	    .editDocument(siteScope, override)
220	    .pipe(Effect.result);
221	  if (edited._tag === 'Failure') return issueResponse(edited.failure);
222	
223	  if (intent === 'save-draft') {
224	    return redirect('/admin/content?status=Draft%20saved.');
225	  }
226	
227	  // publish: promote the just-saved draft to the live document, drop the draft,
228	  // and bust the read cache so the change is live on the next public read.
229	  const published = yield* editor.publish(siteScope).pipe(Effect.result);
230	  if (published._tag === 'Failure') return issueResponse(published.failure);
231	  return redirect(
232	    '/admin/content?status=Published.%20Live%20on%20the%20next%20page%20load.',
233	  );
234	});
