431	/**
432	 * The per-item structural controls (ADR 0006): move up / down (a reorder
433	 * submitting the full new id order so a partial/stale order never drops an item)
434	 * and remove. Rendered next to each list item; the `ids` is the list's current
435	 * id order so a move computes the swapped permutation client-side.
436	 */
437	function ItemControls({
438	  listPath,
439	  ids,
440	  index,
441	}: {
442	  readonly listPath: string;
443	  readonly ids: readonly string[];
444	  readonly index: number;
445	}) {
446	  const id = ids[index];
447	  if (id === undefined) return null;
448	  // Swap two positions to compute the reorder permutation, guarding the bounds
449	  // so the disabled edge buttons (first item's "↑", last item's "↓") never
450	  // index past the array; out of range, the order is returned unchanged.
451	  const swapped = (a: number, b: number): string => {
452	    const aId = ids[a];
453	    const bId = ids[b];
454	    if (aId === undefined || bId === undefined) return ids.join(',');
455	    const next = [...ids];
456	    next[a] = bId;
457	    next[b] = aId;
458	    return next.join(',');
459	  };
460	  return (
461	    <div className="flex items-center gap-1">
462	      <ListOpButton
463	        listPath={listPath}
464	        kind="reorder"
465	        value={index > 0 ? swapped(index, index - 1) : ids.join(',')}
466	        label="↑"
467	        disabled={index === 0}
468	      />
469	      <ListOpButton
470	        listPath={listPath}
471	        kind="reorder"
472	        value={index < ids.length - 1 ? swapped(index, index + 1) : ids.join(',')}
473	        label="↓"
474	        disabled={index === ids.length - 1}
475	      />
476	      <ListOpButton
477	        listPath={listPath}
478	        kind="remove"
479	        value={id}
480	        label="Remove"
481	        variant="danger"
482	      />
483	    </div>
484	  );
485	}
